const records = $input.item.json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    agent_name: r.fields.agent_name || '',
    website: r.fields.website || '',
    domain: r.fields.domain || '',
    phone: r.fields.phone || '',
    city: r.fields.city || '',
    state: r.fields.state || ''
  }
}));

// Mark as Audited with no website signal when fetch fails.
const record = $('Split Into Items').item.json;
return [{ json: { ...record, has_live_chat: false, contact_form_found: false, audit_failed: true } }];

// Live chat detection: scan for known widget script signatures.
// Contact form detection: scan for <form> elements with email/text inputs.
const html = $input.item.json.data || $input.item.json || '';
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);
const htmlLower = htmlStr.toLowerCase();

const CHAT_PATTERNS = [
  'tawk.to', 'tawk_api', 'drift.com', '__drift',
  'intercom.io', 'intercomsettings', 'intercom(',
  'livechatinc', 'lc_api', '__lc',
  'tidio', 'tidioChat',
  'crisp.chat', 'window.$crisp',
  'freshchat', 'freshdesk',
  'zopim', 'zendesk',
  'olark',
  'liveperson',
  'snapengage',
  'smartsupp'
];

const has_live_chat = CHAT_PATTERNS.some(p => htmlLower.includes(p.toLowerCase()));

// Detect contact form: look for <form> tags with email or message fields,
// or common contact page patterns.
const hasFormTag = /<form[^>]*>/i.test(htmlStr);
const hasEmailInput = /type=["']email["']/i.test(htmlStr);
const hasMessageField = /name=["'](message|comments?|body|inquiry)["']/i.test(htmlStr);
const hasContactLink = /href=["'][^"']*contact[^"']*["']/i.test(htmlStr);
const contact_form_found = hasFormTag && (hasEmailInput || hasMessageField);

// Extract the form action URL for submission (first form with an action attribute).
let form_action = null;
const formMatch = htmlStr.match(/<form[^>]*action=["']([^"']+)["']/i);
if (formMatch) {
  try {
    const record = $('Split Into Items').item.json;
    const base = new URL(record.website.startsWith('http') ? record.website : 'https://' + record.website);
    form_action = new URL(formMatch[1], base).toString();
  } catch(e) {
    form_action = formMatch[1];
  }
}

// Extract input field names for form submission.
const nameFields = [];
const fieldRegex = /name=["']([^"']+)["']/gi;
let match;
while ((match = fieldRegex.exec(htmlStr)) !== null) {
  nameFields.push(match[1]);
}

const record = $('Split Into Items').item.json;
return [{
  json: {
    ...record,
    has_live_chat,
    contact_form_found,
    form_action,
    form_fields: nameFields.slice(0, 20),
    has_contact_link: hasContactLink,
    audit_failed: false
  }
}];

// Build a POST body using common field name patterns found on the form.
// Maps detected field names to plausible values.
const record = $input.item.json;
const fields = record.form_fields || [];

const NAME_PATTERNS = ['name', 'full_name', 'fullname', 'your-name', 'fname', 'first_name', 'contact_name'];
const EMAIL_PATTERNS = ['email', 'your-email', 'email-address', 'e-mail', 'contact_email'];
const PHONE_PATTERNS = ['phone', 'telephone', 'tel', 'phone_number', 'your-phone'];
const MESSAGE_PATTERNS = ['message', 'comments', 'comment', 'body', 'inquiry', 'question', 'msg'];

const payload = {};
for (const field of fields) {
  const f = field.toLowerCase();
  if (NAME_PATTERNS.some(p => f.includes(p))) payload[field] = 'Alex Thompson';
  else if (EMAIL_PATTERNS.some(p => f.includes(p))) payload[field] = $env.INQUIRY_EMAIL_ALIAS || 'inquiry@example.com';
  else if (PHONE_PATTERNS.some(p => f.includes(p))) payload[field] = '555-0100';
  else if (MESSAGE_PATTERNS.some(p => f.includes(p))) payload[field] = 'Hi, I am interested in buying a home in your area and was hoping to get in touch with an agent. Could you please reach out when you have a chance? Thank you.';
}

// Fallback: always ensure email + message are present under common names.
if (!payload.email && !payload['your-email']) payload.email = $env.INQUIRY_EMAIL_ALIAS || 'inquiry@example.com';
if (!payload.message && !payload.comments) payload.message = 'Hi, I am interested in buying a home in your area. Please reach out when you have a chance. Thank you.';

return [{ json: { ...record, inquiry_payload: payload, inquiry_sent_at: new Date().toISOString() } }];

// Form submission succeeded — attach the inquiry timestamp from the build step.
const buildNode = $('Build Inquiry Payload').item.json;
return [{ json: { ...buildNode, inquiry_submitted: true } }];

// Submission failed (4xx/5xx or network error) — still record that we tried.
const buildNode = $('Build Inquiry Payload').item.json;
return [{ json: { ...buildNode, inquiry_submitted: false } }];

// No contact form found — record that we couldn't send an inquiry.
const record = $input.item.json;
return [{ json: { ...record, inquiry_submitted: false, inquiry_sent_at: null } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
const r = $input.item.json;
const chatStatus = r.has_live_chat ? '✅ Has live chat' : '❌ No live chat';
const formStatus = r.contact_form_found ? `✅ Form found${r.inquiry_submitted ? ' + inquiry sent' : ' (submit failed)'}` : '❌ No form';
return [{ json: { slackUrl, slackBody: { text: `🔍 *RE Audit: ${r.agent_name || 'Unknown'}*\n${chatStatus}\n${formStatus}\n📍 ${r.city}, ${r.state}` } } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: { slackUrl, slackBody: { text: `🚨 *RE Workflow B Error*\n${err.execution?.error?.message || 'Unknown error'}` } } }];
